class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.size();
        int res = INT_MAX;
        for (int d = 1; d <= n / 2; d++) {
            if (n % d == 0) {
                int cnt = 0;
                for (int i = 0; i < d; i++) {
                    int j = i;
                    while (j < n) {
                        if (s[j] != s[j - i]) cnt++;
                        j += d;
                    }
                }
                res = min(res, cnt);
            }
        }
        return res;
    }
};
